#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
const int MOD = 1e9 + 7;
bool not_prime[4010];
int prime[4010], tot;
void init (int n) {
    for (int i = 2; i <= n; i++) {
		if (!not_prime[i]) {
        	prime[++tot] = i;
        	for (int j = i + i; j <= n; j += i) {
            	not_prime[j] = 1;
            }
    	}
    }
}
bool check (int x) {
    int y = pow (x, 0.5);
    if (y * y == x || (y + 1) * (y + 1) == x) {
    	return true;
	}
    y = pow (x, 1.0 / 3);
    if (y * y * y == x 
	|| (y + 1) * (y + 1) * (y + 1) == x 
	|| (y + 2) * (y + 2) * (y + 2) == x) {
		return true;
	}
    return false;
}
signed main() {
    init (4000);
    int T;
    cin >> T;
    while (T--) {
        int x;
        cin >> x;
        if (check(x)) {
            cout << "yes\n";
            continue;
        }
        bool flag = true;
        for (int i = 1; i <= tot; i++) {
			if (x % prime[i] == 0) {
	            int now = 0;
    	        while (x % prime[i] == 0) {
        	        now++;
            	    x /= prime[i] ;
            	}
            	if (now == 1) {
                	flag = false;
                	break;
            	}
        	}
        }
        if (flag & check(x)) {
            cout << "yes\n";
            continue;
        } else {
        	cout << "no\n";
        }
    }
    return 0;
}
